import json
import re
import requests
from requests.exceptions import RequestException

def get_one_page(url, headers):
    try:
        response = requests.get(url, headers=headers)
        if response.status_code == 200:
            return response.text
        return None
    except RequestException:
        return None

def parse_one_page(html):
    pattern = re.compile(
        '<dd>.*?board-index.*?>(\d+)</i>.*?data-src="(.*?)".*?name"><a.*?>(.*?)</a>.*?star">(.*?)</p>.*?releasetime">(.*?)</p>.*?integer">(.*?)</i>.*?fraction">(.*?)</i>.*?</dd>',
        re.S)
    items = re.findall(pattern, html)
    for item in items:
        yield {
            'rank': item[0],
            'cover_image': item[1],
            'title': item[2],
            'main_actors': item[3].strip()[3:],
            'release_time': item[4].strip()[5:],
            'rating': item[5] + item[6],
        }

def write_to_file(content):
    with open('result.json', 'a', encoding='utf-8') as f:
        f.write(json.dumps(content, ensure_ascii=False) + '\n')

def main(offset):
    url = f'http://fictional-movie-site.com/board/4?offset={offset}'
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/62.0.3202.62 Safari/537.36'}
    html = get_one_page(url, headers)
    if html:
        for item in parse_one_page(html):
            print(item)
            write_to_file(item)

if __name__ == '__main__':
    for i in range(10):
        main(i * 10)
