import pandas as pd

class LinearPearsonAnomalyDetector:
    def __init__(self):
        self.dataframe = None
        self.corr_threshold = None

    def __generate_dataframe(self, values):
        dict_from_values = {'variable': values, 'index': range(len(values))}
        return pd.DataFrame(dict_from_values)

    def __get_pearson(self, dataframe):
        return dataframe.corr()['variable']['index']

    def train(self, values):
        self.dataframe = self.__generate_dataframe(values)
        self.corr_threshold = abs(self.__get_pearson(self.dataframe))
        return self.corr_threshold

    def is_anomalous(self, value):
        new_value_row = pd.Series([value, len(self.dataframe.index)], ['variable', 'index'])
        new_dataframe = self.dataframe.append(new_value_row, ignore_index=True)
        return abs(self.__get_pearson(new_dataframe)) < self.corr_threshold

# Test cases to verify the solution correctness
if __name__ == "__main__":
    detector = LinearPearsonAnomalyDetector()

    # Training with a sequence that has a strong linear relationship
    baseline_corr = detector.train([1, 2, 3, 4, 5])
    print(f"Baseline correlation: {baseline_corr}")

    # Testing with a value that follows the linear relationship
    print(f"Is value 6 anomalous? {detector.is_anomalous(6)}")  # Expected: False

    # Testing with a value that does not follow the linear relationship
    print(f"Is value 100 anomalous? {detector.is_anomalous(100)}")  # Expected: True
