import unittest

# Define the line classes
class StringLine:
    def __init__(self, content):
        self.content = content

class EmptyStringLine(StringLine):
    def __init__(self):
        super().__init__('')

class CellSeparatorLine(StringLine):
    def __init__(self):
        super().__init__('')

class DatabricksCellSeparatorLine(StringLine):
    def __init__(self):
        super().__init__('%md')

# Define the transformer class
class CellSeparatorsTransformer:
    def transform(self, lines):
        transformed_lines = []
        for line in lines:
            if isinstance(line, CellSeparatorLine):
                transformed_lines.append(DatabricksCellSeparatorLine())
            else:
                transformed_lines.append(line)
        return transformed_lines

# Define the test case
class CellSeparatorsTransformerTest(unittest.TestCase):

    def setUp(self):
        self.transformer = CellSeparatorsTransformer()

    def test_transform(self):
        input_lines = [
            CellSeparatorLine(),
            EmptyStringLine(),
            StringLine('print("Hello world")'),
            EmptyStringLine(),
            CellSeparatorLine(),
            EmptyStringLine(),
            StringLine('a = 5'),
        ]

        expected_lines = [
            DatabricksCellSeparatorLine(),
            EmptyStringLine(),
            StringLine('print("Hello world")'),
            EmptyStringLine(),
            DatabricksCellSeparatorLine(),
            EmptyStringLine(),
            StringLine('a = 5'),
        ]

        result = self.transformer.transform(input_lines)
        for expected, actual in zip(expected_lines, result):
            self.assertEqual(expected.content, actual.content)

# Run the test case
