    def __init__(self, nombre, fechaPublicacion, generos, descripcion):
        self.nombre = nombre
        self.fechaPublicacion = fechaPublicacion
        self.generos = generos if isinstance(generos, list) else []
        self.descripcion = descripcion
        self.albumsSimilares = []
        self.playsCanciones = {}

