import l20n.format.lol.ast as ast
import pyast
import sys

def read_file(path):
    try:
        with open(path, 'r') as f:
            return f.read()
    except IOError as e:
        raise IOError(f"Error reading file {path}: {e}")

def get_lol(path):
    s = read_file(path)
    parser = Parser()
    try:
        lol = parser.parse(s)
    except ParserError as e:
        raise ParserError(f"Cannot parse LOL file: {e}")
    return lol

def validate_lol_file(path):
    errors = []
    warnings = []
    try:
        lol = get_lol(path)
    except (IOError, ParserError) as e:
        errors.append(str(e))
        return (errors, warnings)

    ids = set()
    for i in lol.body:
        if isinstance(i, (ast.Entity, ast.Macro)):
            if i.id.name in ids:
                warnings.append(f'Duplicated ID {i.id.name}')
            else:
                ids.add(i.id.name)
    return (errors, warnings)

# Test cases to verify the solution correctness
