from datetime import datetime, timedelta
from abc import ABCMeta, abstractmethod

class CacheItemInterface(metaclass=ABCMeta):

    @abstractmethod
    def get_key(self):
        pass

    @abstractmethod
    def get(self):
        pass

    @abstractmethod
    def is_hit(self):
        pass

    @abstractmethod
    def set(self, key, value):
        pass

    @abstractmethod
    def expires_at(self, timestamp):
        pass

    @abstractmethod
    def expires_after(self, seconds):
        pass

class CacheItem(CacheItemInterface):
    def __init__(self, key=None, value=None):
        self._key = key
        self._value = value
        self._expiration = None

    def get_key(self):
        return self._key

    def get(self):
        if self.is_hit():
            return self._value
        return None

    def is_hit(self):
        if self._expiration is None or datetime.now() < self._expiration:
            return True
        return False

    def set(self, key, value):
        self._key = key
        self._value = value
        return self

    def expires_at(self, timestamp):
        if not isinstance(timestamp, datetime):
            raise ValueError("timestamp must be a datetime object")
        self._expiration = timestamp
        return self

    def expires_after(self, seconds):
        if not isinstance(seconds, (int, float)):
            raise ValueError("seconds must be a number")
        self._expiration = datetime.now() + timedelta(seconds=seconds)
        return self

# Test cases
cache = CacheItem()

# Test set and get
cache.set('username', 'john_doe')
assert cache.get() == 'john_doe', "Value retrieved should be 'john_doe'"

# Test expiration
cache.expires_after(2)  # Expires after 2 seconds
assert cache.is_hit() == True, "Cache should be a hit before expiration"
time.sleep(3)  # Wait for expiration
assert cache.is_hit() == False, "Cache should not be a hit after expiration"

# Test get_key
assert cache.get_key() == 'username', "Key retrieved should be 'username'"

# Test expires_at
future_time = datetime.now() + timedelta(seconds=5)
cache.expires_at(future_time)
assert cache.is_hit() == True, "Cache should be a hit before set expiration"
time.sleep(6)  # Wait for expiration
assert cache.is_hit() == False, "Cache should not be a hit after set expiration"

print("All test cases passed!")
