class TreeNode(object):
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

    def insert(self, b):
        if self.val:
            if b < self.val:
                if self.left is None:
                    self.left = TreeNode(b)
                else:
                    self.left.insert(b)
            elif b > self.val:
                if self.right is None:
                    self.right = TreeNode(b)
                else:
                    self.right.insert(b)
        else:
            self.val = b

class Solution(object):
    def invertTree(self, root):
        if root is None:
            return None
        inverted = TreeNode(root.val)
        inverted.left = self.invertTree(root.right)
        inverted.right = self.invertTree(root.left)
        return inverted

    def preOrderTraversal(self, root):
        result = []
        if root:
            result.append(root.val)
            result.extend(self.preOrderTraversal(root.left))
            result.extend(self.preOrderTraversal(root.right))
        return result

if __name__ == '__main__':
    n = int(input())
    def sinsert(c):
        tree = None
        for i in c:
            if tree is None:
                tree = TreeNode(i)
            else:
                tree.insert(i)
        return tree

    for _ in range(n):
        T1 = sinsert(list(map(int, input().split(' '))))
        S = Solution()
        inverted_tree = S.invertTree(T1)
        print(' '.join(map(str, S.preOrderTraversal(inverted_tree))))
