import os
import json
from pathlib import Path

# Global variable to store the project path
project_path = None

def set_project_path(path):
    """Sets the global project path."""
    global project_path
    project_path = path

def read_current_cfg(name="config.json"):
    """Reads the current configuration from the data directory."""
    path = os.path.join(project_path, "data", name)
    if not Path(path).is_file():
        return None
    with open(path, "r") as f:
        cfg = json.load(f)
        return cfg

def get_results_path(id):
    """Returns the path to the results directory for a given id."""
    return os.path.join(project_path, "results", str(id))

def read_result_cfg(id):
    """Reads the configuration for a specific result."""
    path = os.path.join(get_results_path(id), "config_" + str(id) + ".json")
    if Path(path).is_file():
        with open(path, "r") as f:
            cfg = json.load(f)
            return cfg
    else:
        return None

def write_config(cfg, file_name="config.json"):
    """Writes the given configuration to a file."""
    with open(os.path.join(project_path, "data", file_name), "w") as write_json:
        json.dump(cfg, write_json, indent=2, sort_keys=True)

def flt(x):
    """Determines the type of x and calls the appropriate flattening function."""
    if isinstance(x, dict):
        return flt_dict(x)
    elif isinstance(x, list):
        return flt_lst(x)
    elif isinstance(x, tuple):
        return flt_tuple(x)
    else:
        return x

def flt_dict(cfg, parent_key='', sep='.'):
    """Flattens a dictionary configuration."""
    items = []
    for k, v in cfg.items():
        new_key = f"{parent_key}{sep}{k}" if parent_key else k
        if isinstance(v, dict):
            items.extend(flt_dict(v, new_key, sep=sep).items())
        elif isinstance(v, (list, tuple)):
            items.extend(flt_lst(v, new_key).items())
        else:
            items.append((new_key, v))
    return dict(items)

def flt_lst(lst, parent_key='', sep='.'):
    """Flattens a list configuration."""
    items = {}
    for i, v in enumerate(lst):
        new_key = f"{parent_key}{sep}{i}"
        if isinstance(v, dict):
            items.update(flt_dict(v, new_key, sep=sep))
        elif isinstance(v, (list, tuple)):
            items.update(flt_lst(v, new_key))
        else:
            items[new_key] = v
    return items

def flt_tuple(tpl, parent_key='', sep='.'):
    """Flattens a tuple configuration."""
    return flt_lst(tpl, parent_key, sep)

# Test cases to verify the solution correctness
if __name__ == "__main__":
    # Set the project path for testing
    set_project_path('/path/to/project')

    # Test flattening functions
    nested_cfg = {'a': {'b': 1, 'c': [2, 3]}, 'd': (4, 5)}
    flat_cfg = flt(nested_cfg)
    assert flat_cfg == {'a.b': 1, 'a.c.0': 2, 'a.c.1': 3, 'd.0': 4, 'd.1': 5}

    # Test reading and writing configurations
    test_cfg = {'key': 'value'}
    write_config(test_cfg, 'test_config.json')
    read_cfg = read_current_cfg('test_config.json')
    assert read_cfg == test_cfg

    print("All test cases passed.")
