        self.name = name
        self.roles = []

class RoleManager:
    def __init__(self, server):
        self.server = server

    def list_roles(self):
        return self.server.roles

    def add_role_to_user(self, user, role_name):
        role = next((role for role in self.server.roles if role.name == role_name), None)
        if role is None:
            raise ValueError(f"Role '{role_name}' does not exist.")
        if role in user.roles:
            raise ValueError(f"User '{user.name}' already has the role '{role_name}'.")
        user.roles.append(role)

    def remove_role_from_user(self, user, role_name):
        role = next((role for role in user.roles if role.name == role_name), None)
        if role is None:
            raise ValueError(f"User '{user.name}' does not have the role '{role_name}'.")
        user.roles.remove(role)

    def has_role(self, user, role_name):
        return any(role.name == role_name for role in user.roles)

