import abc

class TableFormatter(abc.ABC):
    @abc.abstractmethod
    def headings(self, headers):
        """
        Emit the table headings.
        """
        pass

    @abc.abstractmethod
    def row(self, rowdata):
        """
        Emit a single row of table data.
        """
        pass


class TextTableFormatter(TableFormatter):
    def headings(self, headers):
        for h in headers:
            print(f'{h:>10s}', end=' ')
        print()
        print(('-' * 10 + ' ') * len(headers))

    def row(self, rowdata):
        for d in rowdata:
            print(f'{d:>10s}', end=' ')
        print()


class CSVTableFormatter(TableFormatter):
    def headings(self, headers):
        print(','.join(headers))

    def row(self, rowdata):
        print(','.join(rowdata))


class HTMLTableFormatter(TableFormatter):
    def headings(self, headers):
        print("<tr>", end='')
        for h in headers:
            print(f"<th>{h}</th>", end='')
        print("</tr>", end='')
        print()

    def row(self, rowdata):
        print("<tr>", end='')
        for d in rowdata:
            print(f"<td>{d}</td>", end='')
        print("</tr>", end='')
        print()


class FormatError(Exception):
    pass


def create_formatter(fmt):
    if fmt == 'txt':
        formatter = TextTableFormatter()
    elif fmt == 'csv':
        formatter = CSVTableFormatter()
    elif fmt == 'html':
        formatter = HTMLTableFormatter()
    else:
        raise FormatError(f'Unknown format {fmt}')
    return formatter


def print_table(lst, colnames, formatter):
    formatter.headings(colnames)
    for obj in lst:
        rowdata = [str(getattr(obj, colname)) for colname in colnames]
        formatter.row(rowdata)


# Example usage:
class Item:
    def __init__(self, name, quantity, price):
        self.name = name
        self.quantity = quantity
        self.price = price

items = [
    Item('Widget', 10, 2.5),
    Item('Gadget', 5, 5.0),
    Item('Doohickey', 1, 10.0)
]

colnames = ['name', 'quantity', 'price']

# Test cases
print("Text Table:")
txt_formatter = create_formatter('txt')
print_table(items, colnames, txt_formatter)

print("\nCSV Table:")
csv_formatter = create_formatter('csv')
print_table(items, colnames, csv_formatter)

print("\nHTML Table:")
html_formatter = create_formatter('html')
print_table(items, colnames, html_formatter)
