"""Module for geometric shapes: Base, Rectangle, and Square."""

import unittest

class Base:
    __nb_objects = 0

    def __init__(self, id=None):
        if id is not None:
            self.id = id
        else:
            Base.__nb_objects += 1
            self.id = Base.__nb_objects

class Rectangle(Base):
    def __init__(self, width, height, x=0, y=0, id=None):
        super().__init__(id)
        self.width = width
        self.height = height
        self.x = x
        self.y = y

    def __str__(self):
        return f"[Rectangle] ({self.id}) {self.x}/{self.y} - {self.width}/{self.height}"

    def display(self):
        print("\n" * self.y + (" " * self.x + "#" * self.width + "\n") * self.height, end="")

    def update(self, *args, **kwargs):
        attributes = ['id', 'width', 'height', 'x', 'y']
        if args:
            for attr, value in zip(attributes, args):
                setattr(self, attr, value)
        else:
            for key, value in kwargs.items():
                if key in attributes:
                    setattr(self, key, value)

class Square(Rectangle):
    def __init__(self, size, x=0, y=0, id=None):
        super().__init__(size, size, x, y, id)

    def __str__(self):
        return f"[Square] ({self.id}) {self.x}/{self.y} - {self.width}"

    def update(self, *args, **kwargs):
        attributes = ['id', 'size', 'x', 'y']
        if args:
            args = list(args)
            if len(args) > 1:
                args.insert(1, args[1])  # Insert size as both width and height
            super().update(*args)
        else:
            if 'size' in kwargs:
                kwargs['width'] = kwargs['height'] = kwargs['size']
                del kwargs['size']
            super().update(**kwargs)

# Unit tests for the classes
class TestGeometricShapes(unittest.TestCase):
