import random

class Gladiator:
    """Represents a gladiator with attributes and methods for battle simulation."""

    def __init__(self, name, gladiator_class='fighter', gladiator_species='human'):
        self.name = name
        self.gladiator_class = GladiatorClass(gladiator_class)
        self.gladiator_species = GladiatorSpecies(gladiator_species)
        self.hit_points = self.gladiator_class.base_hp
        self.armor_class = self.gladiator_class.base_ac
        self.damage_modifier = self.gladiator_class.damage_mod
        self.gold_coins = random.randint(2, 10)
        self.inventory = {'weapons': [], 'armor': []}

    def attack(self, target):
        attack_roll = random.randint(1, 20) + self.damage_modifier
        if attack_roll > target.armor_class:
            damage = random.randint(1, 8) + self.damage_modifier
            target.hit_points -= damage
            return f'{self.name} successfully attacked {target.name} for {damage} damage!'
        else:
            return f'{self.name} missed the attack on {target.name}.'

    def is_defeated(self):
        return self.hit_points <= 0

    def __repr__(self):
        return f'Gladiator {self.name}, Class: {self.gladiator_class}, Species: {self.gladiator_species}'


class GladiatorClass:
    """Represents a gladiator class with base attributes."""

    class_stats = {
        'fighter': {'base_hp': 12, 'base_ac': 16, 'damage_mod': 2},
        'mage': {'base_hp': 6, 'base_ac': 12, 'damage_mod': 5},
        'archer': {'base_hp': 8, 'base_ac': 14, 'damage_mod': 3}
    }

    def __init__(self, gladiator_class):
        self.gladiator_class = gladiator_class
        self.base_hp = self.class_stats[gladiator_class]['base_hp']
        self.base_ac = self.class_stats[gladiator_class]['base_ac']
        self.damage_mod = self.class_stats[gladiator_class]['damage_mod']

    def __repr__(self):
        return self.gladiator_class


class GladiatorSpecies:
    """Represents a gladiator species."""

    def __init__(self, gladiator_species):
        self.gladiator_species = gladiator_species

    def __repr__(self):
        return self.gladiator_species


def simulate_battle(gladiator1, gladiator2):
    """Simulates a battle between two gladiators and returns the winner."""
    while not gladiator1.is_defeated() and not gladiator2.is_defeated():
        print(gladiator1.attack(gladiator2))
        if gladiator2.is_defeated():
            return f'{gladiator1.name} has won the battle!'
        print(gladiator2.attack(gladiator1))
        if gladiator1.is_defeated():
            return f'{gladiator2.name} has won the battle!'
    return 'The battle ended in a draw.'

# Test cases
gladiator_a = Gladiator('Maximus', 'fighter', 'human')
gladiator_b = Gladiator('Tiberius', 'mage', 'elf')

print(simulate_battle(gladiator_a, gladiator_b))
