from enum import Enum
import numpy as np

# Mock classes and functions to simulate AUV behavior
class Task:
    def __init__(self):
        self.finished = False

class GoToPosition(Task):
    def __init__(self, x, y, depth):
        super().__init__()
        # Simulate task logic here

# Mock AUV state and position
class aslam:
    class sub:
        @staticmethod
        def position():
            # Return the current position of the AUV
            return np.array([0, 0, 0])

# Locale bounds for the AUV's operation area
locale_bounds = [(-100, 100), (-100, 100), (-10, 0)]

class GuardState(Enum):
    RUNNING = 0
    GUARDING = 1

class Guarded(Task):
    def on_first_run(self, *args, **kwargs):
        self.state = GuardState.RUNNING

    def on_run(self, condition, description, desired_task, restore_cls, *args, **kwargs):
        if self.state is GuardState.RUNNING:
            ok = condition()
            if ok:
                desired_task()
                if desired_task.finished:
                    self.finish()
            else:
                print(f'Guarded task running with condition "{description}" was triggered, swapping to restore task')
                self.state = GuardState.GUARDING
                self.restore_instance = restore_cls()

        elif self.state is GuardState.GUARDING:
            self.restore_instance()
            if self.restore_instance.finished:
                print(f'Restore task for guarded task running with condition "{description}" finished, swapping back to main task')
                self.state = GuardState.RUNNING

def within(vec, bounds):
    return all(bounds[ind][0] <= vec[ind] <= bounds[ind][1] for ind in range(len(bounds)))

def center(bounds):
    return np.array([(bound[0] + bound[1]) / 2. for bound in bounds])

def unitize(vec):
    return vec / np.linalg.norm(vec)

def TowardsCenter():
    ctr = center(locale_bounds)
    now = aslam.sub.position()
    direc = unitize(ctr - now)
    dest = direc * 1.
    return GoToPosition(dest[0], dest[1], depth=dest[2])

LocaleBounded = lambda task: Guarded(
    lambda: within(aslam.sub.position(), locale_bounds),
    'avoid locale bound escapement',
    task,
    TowardsCenter
)

# Test cases
if __name__ == "__main__":
    # Create a mock task to simulate AUV behavior
    mock_task = Task()

    # Wrap the mock task with the locale bounded guard
    guarded_task = LocaleBounded(mock_task)

    # Simulate the guarded task running
    guarded_task.on_first_run()
    for _ in range(5):
        guarded_task.on_run()
        if guarded_task.finished:
            break
